// 1. 创建集成模块: src/dashboard/integration/iteration-emitter.ts
export class IterationEventEmitter {
  private realtimeService: RealtimeService

  constructor(realtimeService: RealtimeService) {
    this.realtimeService = realtimeService
  }

  // 迭代开始
  async onIterationStart(data: {
    iterationNumber: number
    requirement: string
  }) {
    await this.realtimeService.broadcast('iteration.started', data)
  }

  // Agent 状态变化
  async onAgentStatusChange(data: {
    agentName: string
    status: 'idle' | 'running' | 'completed' | 'failed'
    currentTask: string
  }) {
    await this.realtimeService.broadcast('agent.status_changed', data)
  }

  // 迭代进度
  async onIterationProgress(data: {
    iterationNumber: number
    phase: string
    progress: number
    message: string
  }) {
    await this.realtimeService.broadcast('iteration.progress', data)
  }

  // 迭代完成
  async onIterationComplete(data: {
    iterationNumber: number
    status: 'success' | 'failed'
    commitInfo?: { commitId: string; files: number; lines: number }
  }) {
    await this.realtimeService.broadcast('iteration.completed', data)
  }
}
```

