#### 任务 2: 完善 WebSocket Store
**优先级**: **P0**  
**工作量**: 1 天  
**文件**: `dashboard/src/stores/websocket.ts`

**问题描述**:
Dashboard.vue 中使用了 `useWebSocketStore()`，但该 store 可能未实现或功能不完整。

**具体任务**:

```typescript
// dashboard/src/stores/websocket.ts
import { defineStore } from 'pinia'
import { ref, computed } from 'vue'

export const useWebSocketStore = defineStore('websocket', () => {
  const ws = ref<WebSocket | null>(null)
  const connected = ref(false)
  const connecting = ref(false)
  const reconnectAttempts = ref(0)
  const maxReconnectAttempts = 5

  // 事件监听器
  const listeners = ref<Map<string, Function[]>>(new Map())

  // 连接
  function connect() {
    if (connected.value || connecting.value) return

    connecting.value = true
    const url = `ws://${window.location.host}/api/ws`

    ws.value = new WebSocket(url)

    ws.value.onopen = () => {
      console.log('✅ WebSocket connected')
      connected.value = true
      connecting.value = false
      reconnectAttempts.value = 0
    }

    ws.value.onmessage = (event) => {
      try {
        const { event: type, data } = JSON.parse(event.data)
        emit(type, data)
      } catch (error) {
        console.error('Failed to parse WebSocket message:', error)
      }
    }

    ws.value.onclose = () => {
      console.log('❌ WebSocket disconnected')
      connected.value = false
      connecting.value = false

      // 自动重连
      if (reconnectAttempts.value < maxReconnectAttempts) {
        reconnectAttempts.value++
        setTimeout(() => connect(), 2000 * reconnectAttempts.value)
      }
    }

    ws.value.onerror = (error) => {
      console.error('WebSocket error:', error)
      connecting.value = false
    }
  }

  // 断开连接
  function disconnect() {
    ws.value?.close()
    ws.value = null
    connected.value = false
  }

  // 监听事件
  function on(event: string, callback: Function) {
    if (!listeners.value.has(event)) {
      listeners.value.set(event, [])
    }
    listeners.value.get(event)!.push(callback)
  }

  // 移除监听
  function off(event: string, callback: Function) {
    const callbacks = listeners.value.get(event)
    if (callbacks) {
      const index = callbacks.indexOf(callback)
      if (index > -1) {
        callbacks.splice(index, 1)
      }
    }
  }

  // 触发事件
  function emit(event: string, data: any) {
    const callbacks = listeners.value.get(event)
    if (callbacks) {
      callbacks.forEach(callback => callback(data))
    }
  }

  // 发送消息
  function send(event: string, data: any) {
    if (ws.value && connected.value) {
      ws.value.send(JSON.stringify({ event, data }))
    }
  }

  return {
    connected,
    connecting,
    connect,
    disconnect,
    on,
    off,
    send
  }
})
```

**验收标准**:
