#### 任务 4: 完善 API 路由
**优先级**: **P0**  
**工作量**: 2 天  
**文件**: `src/dashboard/routes/index.ts`

**具体任务**:

```typescript
// src/dashboard/routes/index.ts
import { FastifyInstance } from 'fastify'
import { IterationService } from '../services/iteration.service'
import { AgentService } from '../services/agent.service'
import { ProjectService } from '../services/project.service'
import { SystemService } from '../services/system.service'
import { RealtimeService } from '../services/realtime.service'

export async function registerRoutes(
  fastify: FastifyInstance,
  services: {
    iterationService: IterationService
    agentService: AgentService
    projectService: ProjectService
    systemService: SystemService
    realtimeService: RealtimeService
  }
) {
  const { iterationService, agentService, projectService, systemService, realtimeService } = services

  // ==================== 系统概览 ====================
  fastify.get('/overview', async (request, reply) => {
    const overview = await systemService.getOverview()
    return reply.send(overview)
  })

  // ==================== 迭代管理 ====================
  fastify.get('/iterations', async (request, reply) => {
    const { page = 1, limit = 20, status } = request.query as any
    const result = await iterationService.list({
      page: Number(page),
      limit: Number(limit),
      status
    })
    return reply.send(result)
  })

  fastify.get('/iterations/:id', async (request, reply) => {
    const { id } = request.params as { id: string }
    const iteration = await iterationService.getById(Number(id))
    if (!iteration) {
      return reply.code(404).send({ error: 'Iteration not found' })
    }
    return reply.send(iteration)
  })

  fastify.get('/iterations/current', async (request, reply) => {
    const current = await iterationService.getCurrent()
    return reply.send(current || { status: 'idle' })
  })

  fastify.post('/iterations/:id/rollback', async (request, reply) => {
    const { id } = request.params as { id: string }
    try {
      const result = await iterationService.rollback(Number(id))
      return reply.send(result)
    } catch (error: any) {
      return reply.code(400).send({ error: error.message })
    }
  })

  // ==================== Agent 管理 ====================
  fastify.get('/agents', async (request, reply) => {
    const agents = await agentService.getAll()
    return reply.send(agents)
  })

  fastify.get('/agents/:name', async (request, reply) => {
    const { name } = request.params as { name: string }
    const agent = await agentService.getByName(name)
    if (!agent) {
      return reply.code(404).send({ error: 'Agent not found' })
    }
    return reply.send(agent)
  })

  fastify.get('/agents/:name/stats', async (request, reply) => {
    const { name } = request.params as { name: string }
    const stats = await agentService.getStats(name)
    return reply.send(stats)
  })

  // ==================== 系统指标 ====================
  fastify.get('/metrics', async (request, reply) => {
    const { period = '1h' } = request.query as { period: string }
    const metrics = await systemService.getMetrics(period)
    return reply.send(metrics)
  })

  // ==================== 健康检查 ====================
  fastify.get('/health', async (request, reply) => {
    const health = await systemService.getHealthStatus()
    return reply.send(health)
  })

  // ==================== 统计数据 ====================
  fastify.get('/stats', async (request, reply) => {
    const stats = await systemService.getStats()
    return reply.send(stats)
  })
}
```

**验收标准**:
- [ ] 所有 API 端点实现完成
- [ ] API 响应时间 < 100ms
