import { defineStore } from 'pinia'
import { useWebSocketStore } from './websocket'
import { SystemService } from '@/services/system.service'

export const useOverviewStore = defineStore('overview', () => {
  const wsStore = useWebSocketStore()
  const systemService = new SystemService()

  // 状态
  const stats = ref({
    totalIterations: 0,
    runningIterations: 0,
    completedIterations: 0,
    failedIterations: 0,
    activeAgents: 0,
    uptime: 0
  })

  const metrics = ref({
    cpuUsage: 0,
    memoryUsage: 0,
    activeConnections: 0
  })

  const loading = ref(false)
  const lastUpdate = ref<Date | null>(null)

  // 获取初始数据
  async function fetchOverview() {
    loading.value = true
    try {
      const data = await systemService.getOverview()
      stats.value = data
    } catch (error) {
      console.error('Failed to fetch overview:', error)
    } finally {
      loading.value = false
    }
  }

  // 订阅实时更新
  function subscribeToUpdates() {
    // 订阅系统指标更新
    wsStore.on('system.metrics', (data) => {
      metrics.value = {
        cpuUsage: data.cpuUsage,
        memoryUsage: data.memoryUsage,
        activeConnections: data.activeConnections
      }
      lastUpdate.value = new Date()
    })

    // 订阅迭代状态变化
    wsStore.on('iteration.status_changed', (data) => {
      if (data.status === 'running') {
        stats.value.runningIterations++
      } else if (data.status === 'completed') {
        stats.value.runningIterations--
        stats.value.completedIterations++
      } else if (data.status === 'failed') {
        stats.value.runningIterations--
        stats.value.failedIterations++
      }
    })
  }

  // 取消订阅
  function unsubscribeFromUpdates() {
    wsStore.off('system.metrics')
    wsStore.off('iteration.status_changed')
  }

  return {
    stats,
    metrics,
    loading,
    lastUpdate,
    fetchOverview,
    subscribeToUpdates,
    unsubscribeFromUpdates
  }
})
```

