// 任务9: WebSocket认证
fastify.get('/api/ws', { websocket: true }, async (connection, req) => {
  // 从查询参数获取token
  const token = new URL(req.url, `http://${req.headers.host}`)
    .searchParams.get('token');

  if (!token) {
    connection.socket.close(1008, '未提供认证令牌');
    return;
  }

  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET);
    connection.socket.userId = decoded.userId;
    logger.info('WebSocket client authenticated:', decoded.userId);
    realtimeService.addClient(connection.socket);
  } catch (error) {
    connection.socket.close(1008, '认证失败');
  }
});
