**完整实现示例**:

```typescript
export class RealtimeService {
  private clients: Set<WebSocket> = new Set();
  private subscriptions: Map<WebSocket, Set<string>> = new Map();
  private heartbeatInterval: NodeJS.Timeout | null = null;

  constructor() {
    this.startHeartbeat();
  }

  addClient(client: WebSocket) {
    this.clients.add(client);
    this.subscriptions.set(client, new Set());

    client.on('close', () => {
      this.removeClient(client);
    });
  }

  removeClient(client: WebSocket) {
    this.clients.delete(client);
    this.subscriptions.delete(client);
  }

  subscribe(client: WebSocket, channel: string) {
    const channels = this.subscriptions.get(client);
    if (channels) {
      channels.add(channel);
    }
  }

  broadcast(event: string, data: any, channel?: string) {
    const message = JSON.stringify({ event, data, timestamp: new Date().toISOString() });

    this.clients.forEach(client => {
      if (this.shouldSend(client, channel)) {
        if (client.readyState === WebSocket.OPEN) {
          client.send(message);
        }
      }
    });
  }

  private shouldSend(client: WebSocket, channel?: string): boolean {
    if (!channel) return true; // 广播到所有客户端
    const channels = this.subscriptions.get(client);
    return channels ? channels.has(channel) : false;
  }

  private startHeartbeat() {
    this.heartbeatInterval = setInterval(() => {
      const message = JSON.stringify({ event: 'ping', data: null });
      this.clients.forEach(client => {
        if (client.readyState === WebSocket.OPEN) {
          client.send(message);
        }
      });
    }, 30000); // 每30秒
  }

  stop() {
    if (this.heartbeatInterval) {
      clearInterval(this.heartbeatInterval);
    }
  }
}
```

